def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        cap = bins[i]
        if cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / cap
        if ratio > 1:
            priorities[i] = float('inf')
            continue
        score = 0.0
        multiplier = 1.0
        for j in range(1, 8):
            if j % 3 == 0:
                multiplier *= 1.1
            if ratio < 0.1 * j:
                score += (j ** 2) * (1 - ratio) * multiplier
            else:
                score += (j) * (np.exp(-ratio * j)) * multiplier
            if j % 2 == 0 and cap % j == 0:
                score *= 1.05
            elif j % 2 == 1 and cap % j != 0:
                score *= 0.95
        if cap > item * 3:
            for k in range(1, 4):
                if (cap - item * k) % 2 == 0:
                    score += np.log1p(cap - item * k) / (k + 1)
                else:
                    score -= np.sqrt(abs(cap - item * k)) / (k + 2)
        if score > 0:
            priorities[i] = -score / (cap + 1)
        else:
            priorities[i] = -score * np.log1p(cap + 1)
    return priorities
